/**
 * Expected body JSON:
 * {
 *   "mushroomprocess_product_id": "PROD-....",
 *   "storage_location_name": "Location Name"
 * }
 */
const body = $json.body || $json;
const mushroomprocess_product_id = body.mushroomprocess_product_id || body.product_id || null;
const storage_location = body.storage_location_name || body.storage_location || null;

if (!mushroomprocess_product_id) {
  throw new Error('Missing mushroomprocess_product_id');
}

if (!storage_location) {
  throw new Error('Missing storage_location_name');
}

return [{ json: { mushroomprocess_product_id, storage_location } }];
